/**
 * A CDS tranche, resolved for pricing.
 * <p>
 * This is the resolved form of {@link CdsTranche} and is an input to the pricers.
 */
@BeanDefinition
public final class ResolvedCdsTranche
    implements ResolvedProduct, ImmutableBean, Serializable {

  @PropertyDefinition(validate = "notNull")
  private final BuySell buySell;
  @PropertyDefinition(validate = "notNull")
  private final ImmutableList<StandardId> legalEntityIds;
  @PropertyDefinition(validate = "notEmpty")
  private final ImmutableList<CreditCouponPaymentPeriod> paymentPeriods;
  @PropertyDefinition(validate = "notNull")
  private final LocalDate protectionEndDate;
  @PropertyDefinition(validate = "notNull")
  private final DayCount dayCount;
  @PropertyDefinition(validate = "notNull")
  private final PaymentOnDefault paymentOnDefault;
  @PropertyDefinition(validate = "notNull")
  private final ProtectionStartOfDay protectionStart;
  @PropertyDefinition(validate = "notNull")
  private final DaysAdjustment stepinDateOffset;
  @PropertyDefinition(validate = "notNull")
  private final DaysAdjustment settlementDateOffset;
  @PropertyDefinition(validate = "notNull")
  private final Currency currency;
  @PropertyDefinition(validate = "ArgChecker.notNegativeOrZero")
  private final double notional;
  @PropertyDefinition(validate = "ArgChecker.notNegative")
  private final double fixedRate;
  @PropertyDefinition(validate = "ArgChecker.inRangeInclusive")
  private final double attachmentPoint;
  @PropertyDefinition(validate = "ArgChecker.inRangeInclusive")
  private final double detachmentPoint;

  // AUTOGENERATED META AND BUILDER SECTIONS FOLLOW STANDARD PATTERN

  public LocalDate getAccrualStartDate() {
    return paymentPeriods.get(0).getStartDate();
  }

  public LocalDate getAccrualEndDate() {
    return paymentPeriods.get(paymentPeriods.size() - 1).getEndDate();
  }

  /**
   * Gets the tranche loss amount from a total loss on the index.
   * 
   * @param totalIndexLoss the total loss on the index notional
   * @return the loss applicable to this tranche
   */
  public double getTrancheLossAmount(double totalIndexLoss) {
    double attachmentLoss = attachmentPoint * 100.0;  // in basis points
    double detachmentLoss = detachmentPoint * 100.0;
    double lossLow = Math.max(0.0, Math.min(totalIndexLoss, detachmentLoss) - attachmentLoss);
    return Math.max(0.0, lossLow);
  }

  public static ResolvedCdsTranche.Meta meta() {
    return ResolvedCdsTranche.Meta.INSTANCE;
  }

  public static ResolvedCdsTranche.Builder builder() {
    return new ResolvedCdsTranche.Builder();
  }

  // ... full builder and meta implementation ...
}
