  @ImmutableDefaults
  private static void applyDefaults(Builder builder) {
    builder.dayCount = DayCounts.ACT_360;
    builder.paymentOnDefault = PaymentOnDefault.ACCRUED_PREMIUM;
    builder.protectionStart = ProtectionStartOfDay.BEGINNING;
    builder.stepinDateOffset = DaysAdjustment.ofCalendarDays(1);
  }

  @ImmutablePreBuild
  private static void preBuild(Builder builder) {
    if (builder.settlementDateOffset == null && builder.underlyingIndex != null) {
      builder.settlementDateOffset =
          DaysAdjustment.ofBusinessDays(3, builder.underlyingIndex.getPaymentSchedule().getBusinessDayAdjustment().getCalendar());
    }
    // Validate that attachment < detachment
    if (builder.attachmentPoint >= 0 && builder.detachmentPoint >= 0) {
      ArgChecker.inRange(builder.attachmentPoint, 0.0, builder.detachmentPoint, "attachmentPoint", "detachmentPoint");
      ArgChecker.inRange(builder.detachmentPoint, builder.attachmentPoint, 1.0, "detachmentPoint", "1.0");
    }
  }

